-- 20260602_add_delivery_status_to_messages.sql\n\n-- Add a delivery_status column to messages table to track message lifecycle\n-- Possible values: 'sent', 'delivered', 'read', 'failed'\n\nALTER TABLE messages\nADD COLUMN delivery_status ENUM('sent','delivered','read','failed') NOT NULL DEFAULT 'sent';\n\n-- Index for fast queries on delivery status\nCREATE INDEX idx_messages_delivery_status ON messages(delivery_status);\n
